import{c as l,Q as r,j as t,g as e,n as i}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"关于筹款的演讲辞","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/186-关于筹款的演讲辞.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/186-关于筹款的演讲辞.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/186-关于筹款的演讲辞.md"};function o(s,a,n,m,d,_){return r(),t("div",null,[...a[0]||(a[0]=[e("h1",{id:"关于筹款的演讲辞",tabindex:"-1"},[i("关于筹款的演讲辞 "),e("a",{class:"header-anchor",href:"#关于筹款的演讲辞","aria-label":'Permalink to "关于筹款的演讲辞"'},"​")],-1),e("p",null,"关于筹款的演讲辞 可是，要举例子我用不着到希腊去找，佛罗伦萨就有的是。1500年9 月，瓦伦蒂诺率领部队从罗马出发，人们还不清楚他是要穿越托斯卡纳， 还是要进入罗马涅。我们整个城市都疑虑重重，因为它毫无防卫之力，每 个人都在祈求天主给我们点时间。可是，当我们看到他扭身转向佩萨罗， 因而危险并不是马上出现，于是人们就都陷入了一种盲目的自信，以致没 有办法劝说你们做任何防备。之前也不是没有把各种预言和危险都告诉你 们，这些事情后来都出现了。但你们很固执，都不相信。末了，1501年4 月26日聚集在此地，你们听说丢了法恩扎，你们看到了你们的正义旗手的 眼泪，他是为你们的不信任和冷酷而哭的，他还责令你们要对自己抱以同 情。你们没有时间了，因为，如果是提前两个月做准备，那还可能有效 果，如果是提前六天，那对你们的得救便起不了什么作用了。因为，在5 月4日，你们听说敌军抵达了菲伦佐拉；该城一片混乱，你们开始了解你 们冷酷心肠的后果：你们看到你们的房子被焚烧，财物被劫掠，你们的 属民被杀害、被囚禁，你们的女人被强暴，你们的财产受到了损害，你们 却无从补救。6个月前不愿意付出20达克特的人，现在要损失200达克特； 而20达克特却是无论如何都要付出的。而且，在你们应当责备你们自己的 不信任与固执时，你们却在指责公民们的恶意和贵族们的野心，就像那些 人，他们一直在犯错误，却看不到自己犯了错误；又比如，看到了太阳，",-1),e("p",null,"①拜占庭帝国末代君主君世坦丁十一世 · 帕列奥列格，他在1453年君士坦丁堡被奥斯曼土耳其帝国攻陷 时去世。",-1),e("p",null,"却从来不相信天上也会下雨。正如你们现在所面临的：你们没有想过瓦 伦蒂诺会在8天之内率领他的部队来到你们的土地上，而威尼斯人只要两 天；你们也没想过国王会和瑞士人一起开入伦巴第，而他还没有与德意志 以及西班牙将事情了结，并且在(那波利)王国还有麻烦。你们没有看到 你们处境的脆弱，也没有看到机运的多变。 其他民族常常会因邻人的危险而变得聪明，你们却不会从自己的危险 中长见识，你们对自己没有信心，也没有看到你们正在丧失和已经丧失时 间。这一点你们还会哭泣，并且毫无结果，如果你们不改变想法的话；因 为我要说，机运不会改变她的决定，如果人们不改变做法；如果一桩事情 注定要毁灭，老天也不愿或者不能去维持它。我是不能相信这一毁灭的，因 为我看到你们是自由的佛罗伦萨人，看到你们手里还掌握着自由。对于这一 自由，我相信你们会期望你们拥有那生来自由且愿意自由地生活着的人。 \u2028关于筹款的演讲辞",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
